class ElasticsearchLogHandler(logging.Handler):
    def __init__(
        self,
        app: ElasticsearchApp,
        service: str = "centralized-platform",
        environment: str = "production",
    ) -> None:
        super().__init__()
        self.app = app
        self.service = service
        self.environment = environment

    def emit(self, record: logging.LogRecord) -> None:
        try:
            extra = {
                "module": record.module,
                "function": record.funcName,
                "line": record.lineno,
                "process": record.process,
                "thread": record.thread,
                "pathname": record.pathname,
            }
            if record.exc_info:
                extra["exception"] = self.formatException(record.exc_info) if hasattr(self, "formatException") else str(record.exc_info)

            self.app.index_log(
                level=record.levelname,
                logger_name=record.name,
                message=record.getMessage(),
                service=self.service,
                environment=self.environment,
                trace_id=getattr(record, "trace_id", None),
                extra=extra,
            )
        except Exception:
            self.handleError(record)


def configure_logging(app: ElasticsearchApp) -> logging.Logger:
    logger = logging.getLogger("centralized_logging_app")
    logger.setLevel(logging.INFO)

    stream_handler = logging.StreamHandler(sys.stdout)
    stream_handler.setLevel(logging.INFO)
    stream_handler.setFormatter(
        logging.Formatter("%(asctime)s %(levelname)s %(name)s %(message)s")
    )

    es_handler = ElasticsearchLogHandler(app=app)
    es_handler.setLevel(logging.INFO)

    logger.handlers.clear()
    logger.addHandler(stream_handler)
    logger.addHandler(es_handler)
    return logger


